import{_ as o,c as l,o as a,ag as e}from"./chunks/framework.DK1-H3E1.js";const u=JSON.parse('{"title":"位置编码（Positional Encoding）入门","description":"","frontmatter":{"order":13},"headers":[],"relativePath":"ai/positional-encoding.md","filePath":"ai/positional-encoding.md","lastUpdated":1772197851000}'),r={name:"ai/positional-encoding.md"};function n(t,i,s,d,h,p){return a(),l("div",null,i[0]||(i[0]=[e('<h1 id="位置编码-positional-encoding-入门" tabindex="-1">位置编码（Positional Encoding）入门 <a class="header-anchor" href="#位置编码-positional-encoding-入门" aria-label="Permalink to &quot;位置编码（Positional Encoding）入门&quot;">​</a></h1><blockquote><p>📅 主题：为什么 Transformer 需要位置编码，以及常见实现方式</p></blockquote><h2 id="一、为什么需要位置编码" tabindex="-1">一、为什么需要位置编码 <a class="header-anchor" href="#一、为什么需要位置编码" aria-label="Permalink to &quot;一、为什么需要位置编码&quot;">​</a></h2><p>在 Transformer 里，注意力机制本质上是对一组 token 做加权聚合。<br> 如果只看 token 本身而不看顺序，模型会把句子当成“词袋”：</p><ul><li><code>我爱你</code> 和 <code>你爱我</code> 的 token 集合一样，但语义不同；</li><li>先后顺序、距离远近都会影响句意。</li></ul><p>所以需要给每个 token 加上“位置信息”，告诉模型：</p><ol><li>这个 token 在序列的第几个位置；</li><li>不同 token 之间相隔多远；</li><li>顺序变化是否会改变语义关系。</li></ol><p><strong>位置编码</strong>就是把这些顺序信息注入到模型表示中的方法。</p><hr><h2 id="二、位置编码的基本思路" tabindex="-1">二、位置编码的基本思路 <a class="header-anchor" href="#二、位置编码的基本思路" aria-label="Permalink to &quot;二、位置编码的基本思路&quot;">​</a></h2><p>最常见做法是：在输入层把 <strong>词向量</strong> 与 <strong>位置向量</strong> 相加：</p><p><code>x_i = token_embedding_i + position_embedding_i</code></p><p>其中：</p><ul><li><code>token_embedding_i</code> 表示第 i 个 token 的语义；</li><li><code>position_embedding_i</code> 表示第 i 个位置的位置信息。</li></ul><p>这样同一个词在不同位置会得到不同的最终表示，模型就能利用顺序信息。</p><hr><h2 id="三、经典方案-正弦-余弦位置编码" tabindex="-1">三、经典方案：正弦/余弦位置编码 <a class="header-anchor" href="#三、经典方案-正弦-余弦位置编码" aria-label="Permalink to &quot;三、经典方案：正弦/余弦位置编码&quot;">​</a></h2><p>Transformer 原论文使用的是固定函数位置编码（sin/cos）：</p><ul><li>偶数维：<code>PE(pos, 2i) = sin(pos / 10000^(2i/d_model))</code></li><li>奇数维：<code>PE(pos, 2i+1) = cos(pos / 10000^(2i/d_model))</code></li></ul><p>直观理解：</p><ul><li>不同维度对应不同频率；</li><li>低频维度编码长距离趋势，高频维度编码局部细节；</li><li>组合后可表达丰富的位置模式。</li></ul><h3 id="优点" tabindex="-1">优点 <a class="header-anchor" href="#优点" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ol><li><strong>无需学习参数</strong>：不增加可训练参数量；</li><li><strong>可外推到更长序列</strong>：理论上能给训练时没见过的位置生成编码；</li><li><strong>实现简单稳定</strong>。</li></ol><h3 id="局限" tabindex="-1">局限 <a class="header-anchor" href="#局限" aria-label="Permalink to &quot;局限&quot;">​</a></h3><ul><li>固定函数表达能力有限，不能直接根据任务学习“最优位置表示”。</li></ul><hr><h2 id="四、可学习位置编码-learnable-pe" tabindex="-1">四、可学习位置编码（Learnable PE） <a class="header-anchor" href="#四、可学习位置编码-learnable-pe" aria-label="Permalink to &quot;四、可学习位置编码（Learnable PE）&quot;">​</a></h2><p>另一个常见方案是把位置向量当成可训练参数：</p><ul><li>每个位置一个向量；</li><li>训练过程中与模型参数一起更新。</li></ul><h3 id="优点-1" tabindex="-1">优点 <a class="header-anchor" href="#优点-1" aria-label="Permalink to &quot;优点&quot;">​</a></h3><ul><li>更灵活，可针对任务数据学习到更适配的位置表示。</li></ul><h3 id="局限-1" tabindex="-1">局限 <a class="header-anchor" href="#局限-1" aria-label="Permalink to &quot;局限&quot;">​</a></h3><ul><li>往往受最大训练长度约束，超过长度可能无法直接外推；</li><li>需要额外参数与训练数据支撑。</li></ul><p>很多工程实践会在“可学习能力”和“长度外推能力”之间权衡选择。</p><hr><h2 id="五、相对位置编码-关注-距离关系" tabindex="-1">五、相对位置编码：关注“距离关系” <a class="header-anchor" href="#五、相对位置编码-关注-距离关系" aria-label="Permalink to &quot;五、相对位置编码：关注“距离关系”&quot;">​</a></h2><p>绝对位置编码告诉模型“我在第几位”；<br> 而很多任务更关心“我和你相隔几位”。</p><p><strong>相对位置编码</strong>的核心是把注意力分数与相对距离绑定，例如：</p><ul><li>近邻 token 给予不同偏置；</li><li>对不同相对位移（+1、-1、+10）使用不同参数或函数。</li></ul><p>这类方法常用于：</p><ul><li>长文本建模（更稳健的距离感知）</li><li>结构化序列任务</li></ul><hr><h2 id="六、rope-旋转位置编码-rotary-positional-embedding" tabindex="-1">六、RoPE：旋转位置编码（Rotary Positional Embedding） <a class="header-anchor" href="#六、rope-旋转位置编码-rotary-positional-embedding" aria-label="Permalink to &quot;六、RoPE：旋转位置编码（Rotary Positional Embedding）&quot;">​</a></h2><p>在大模型中非常常见的方案是 <strong>RoPE</strong>。<br> 它不是把位置向量“加到输入上”，而是把位置关系通过“旋转变换”作用到 Q/K 空间：</p><ul><li>让注意力分数天然编码相对位置信息；</li><li>在长上下文场景通常表现更好；</li><li>易与现代 Transformer 结构结合。</li></ul><p>你可以把它理解为：<br><strong>在计算注意力相似度时，把“位置关系”直接融进 QK 匹配过程。</strong></p><hr><h2 id="七、长上下文下的位置编码挑战" tabindex="-1">七、长上下文下的位置编码挑战 <a class="header-anchor" href="#七、长上下文下的位置编码挑战" aria-label="Permalink to &quot;七、长上下文下的位置编码挑战&quot;">​</a></h2><p>当上下文从 4K、8K 扩到 32K、128K 甚至更长时，位置编码会面临：</p><ol><li><strong>外推能力问题</strong>：训练长度之外是否还能稳定工作；</li><li><strong>数值稳定性问题</strong>：长距离位置下相似度分布是否退化；</li><li><strong>任务迁移问题</strong>：在长上下文推理中是否还能保持短上下文能力。</li></ol><p>常见工程手段包括：</p><ul><li>采用更适合长序列的位置编码（如 RoPE 相关改造）；</li><li>上下文扩展训练或继续预训练；</li><li>缓存与分块策略配合（如 KV Cache + 滑窗）。</li></ul><hr><h2 id="八、位置编码在应用侧的启示" tabindex="-1">八、位置编码在应用侧的启示 <a class="header-anchor" href="#八、位置编码在应用侧的启示" aria-label="Permalink to &quot;八、位置编码在应用侧的启示&quot;">​</a></h2><p>虽然业务开发者通常不直接改模型结构，但理解位置编码有助于解释很多现象：</p><ol><li><strong>长文问答性能波动</strong>：模型可能在超长上下文下定位关键信息变弱；</li><li><strong>“中间遗忘”问题</strong>：某些模型对开头/结尾更敏感，对中间段关注不足；</li><li><strong>RAG 注入策略</strong>：检索片段放在什么位置、顺序如何，会影响模型关注度；</li><li><strong>Prompt 结构设计</strong>：关键指令和关键证据尽量靠近问题或输出要求位置。</li></ol><p>换句话说，位置编码不仅是模型内部细节，也会影响上层产品效果。</p><hr><h2 id="九、小结" tabindex="-1">九、小结 <a class="header-anchor" href="#九、小结" aria-label="Permalink to &quot;九、小结&quot;">​</a></h2><ol><li>Transformer 的注意力本身不感知顺序，必须靠位置编码补充位置信息。</li><li>经典做法包括固定的 sin/cos 编码和可学习位置编码。</li><li>相对位置编码更强调 token 间距离关系；RoPE 是当前大模型常用方案。</li><li>长上下文能力与位置编码设计密切相关。</li><li>在实际应用中，理解位置编码有助于优化 Prompt、RAG 片段排布与长文任务表现。</li></ol><p>掌握位置编码，你就补上了 Transformer 基础理论中非常关键的一块拼图。</p>',61)]))}const g=o(r,[["render",n]]);export{u as __pageData,g as default};
